import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, LinearProgress } from '@mui/material';
import response from './response.json';

interface DailyGoal {
  target: number;
  progress: number;
  percentage: number;
}

interface RecentWord {
  word: string;
  meaning: string;
}

interface VocabData {
  wordsLearned: number;
  currentStreak: number;
  dailyGoal: DailyGoal;
  recentWords: RecentWord[];
}

export default function Widget() {
  const vocabData = response.data as VocabData;
  const { wordsLearned, currentStreak, dailyGoal, recentWords } = vocabData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: theme === 'light' ? '#FFFFFF' : '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: primaryColor }}>
              Vocab Builder
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Words Learned: <strong>{wordsLearned}</strong>
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Current Streak: <strong>{currentStreak} days</strong>
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Daily Goal
            </Typography>
            <LinearProgress
              variant="determinate"
              value={dailyGoal.percentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#E0E0E0',
                '& .MuiLinearProgress-bar': {
                  bgcolor: primaryColor,
                  borderRadius: 4,
                }
              }}
            />
            <Typography variant="caption" sx={{ mt: 0.5, color: primaryColor }}>
              {dailyGoal.progress}/{dailyGoal.target} ({dailyGoal.percentage}%)
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Recent Words
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {recentWords.map((word, index) => (
                <Chip
                  key={index}
                  label={word.word}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: accentColor, color: '#FFFFFF' }}
                  title={word.meaning}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
